<template>
  <div>
    <div class="sms_signatures">
      <SpFinder
        ref="finder"
        :split-count="4"
        :search-row-count="4"
        :fixed-row-action="true"
        :setting="setting"
        no-selection
        :hooks="{
          beforeSearch: beforeSearch,
          afterSearch: afterSearch
        }"
        url="/aliyunsms/task/list"
      />
    </div>
    <template v-if="visible">
      <smsMassLogEdit
        :visible="visible"
        :info="info"
        @smsMassLogEditHandler="smsMassLogEditHandler"
        @updateFinder="updateFinder"
      />
    </template>
  </div>
</template>

<script>
import setting_ from '../finder-setting/sms_MassLog'
import { deleteTaskSms } from '@/api/sms'
import smsMassLogEdit from './sms_MassLog_edit.vue'
import Template from '../../../wxapp/template.vue'

export default {
  components: {
    smsMassLogEdit,
    Template
  },
  data() {
    return {
      visible: false,
      info: {},

      search_options: [
        { label: '等待中', value: '1' },
        { label: '群發成功', value: '2' },
        { label: '群發失敗', value: '3' },
        { label: '已撤銷', value: '4' }
      ]
    }
  },
  computed: {
    setting() {
      return setting_(this)
    }
  },
  methods: {
    addTemplate() {
      this.$router.push({ path: this.matchHidePage('edit') })
    },
    beforeSearch(params) {
      return { ...params }
    },
    afterSearch() {},
    async deleteSMS(id) {
      const message = '選擇確定後，群發定時任務將會撤銷。'
      this.$confirm(message, '', {
        confirmButtonText: '確定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(async () => {
        const result = await deleteTaskSms({ id })
        this.$message.success('撤銷成功')
        this.$refs.finder.refresh(true)
      })
    },
    smsMassLogEditHandler() {
      this.visible = false
    },
    updateFinder() {
      this.$refs.finder.refresh(true)
    }
  }
}
</script>
